import{_ as a,o as i,c as s,a2 as n}from"./chunks/framework.BnBoz4Zl.js";const k=JSON.parse('{"title":"第 22 章 把模板、规范与步骤制作成 Skill","description":"当一个任务已经反复成功，下一步不是复制上次的提示词，而是把适用条件、步骤、检查点和配套模板沉淀成 Skill。Skill 是可复用的工作说明，不是绕过制度和审批的自动通行证。 让不同的人面对同类任务时，能使用同一套入口、步骤、边界和验收方法，并在失败时知道如何停止。","frontmatter":{},"headers":[],"relativePath":"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/第 22 章 打造skill：将书和视频蒸馏为可执行 Skill/index.md","filePath":"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/第 22 章 打造skill：将书和视频蒸馏为可执行 Skill/index.md","lastUpdated":1784100816000}'),e={name:"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/第 22 章 打造skill：将书和视频蒸馏为可执行 Skill/index.md"};function t(o,l,r,p,h,d){return i(),s("div",null,[...l[0]||(l[0]=[n(`<h1 id="第-22-章-把模板、规范与步骤制作成-skill" tabindex="-1">第 22 章 把模板、规范与步骤制作成 Skill <a class="header-anchor" href="#第-22-章-把模板、规范与步骤制作成-skill" aria-label="Permalink to &quot;第 22 章 把模板、规范与步骤制作成 Skill&quot;">​</a></h1><p>当一个任务已经反复成功，下一步不是复制上次的提示词，而是把适用条件、步骤、检查点和配套模板沉淀成 Skill。Skill 是可复用的工作说明，不是绕过制度和审批的自动通行证。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>同类任务每月或每周重复出现。</li><li>执行步骤稳定，但输入材料每次不同。</li><li>结果有明确模板和验收标准。</li><li>新手经常在相同步骤出错。</li></ul><h2 id="任务目标" tabindex="-1">任务目标 <a class="header-anchor" href="#任务目标" aria-label="Permalink to &quot;任务目标&quot;">​</a></h2><p>让不同的人面对同类任务时，能使用同一套入口、步骤、边界和验收方法，并在失败时知道如何停止。</p><h2 id="输入材料" tabindex="-1">输入材料 <a class="header-anchor" href="#输入材料" aria-label="Permalink to &quot;输入材料&quot;">​</a></h2><ul><li>已验证的任务样本和复盘记录。</li><li>允许公开或内部使用的模板、规范和检查表。</li><li>常见错误、异常处理和人工确认点。</li><li>Skill 的适用范围、禁止范围和维护责任。</li></ul><h2 id="制作步骤" tabindex="-1">制作步骤 <a class="header-anchor" href="#制作步骤" aria-label="Permalink to &quot;制作步骤&quot;">​</a></h2><ol><li><strong>收集成功样本</strong>：至少确认一次完整任务真正通过验收。</li><li><strong>拆分稳定与变化</strong>：稳定部分写入 Skill，变化部分作为每次任务输入。</li><li><strong>写清触发条件</strong>：说明什么时候应该使用，什么时候不该使用。</li><li><strong>设计执行流程</strong>：每一步说明输入、动作、输出和暂停条件。</li><li><strong>绑定资源</strong>：复用模板、术语表、示例和检查脚本，不把大段资料全塞进说明。</li><li><strong>加入人工闸门</strong>：外发、覆盖、审批、结论和批量写入前暂停。</li><li><strong>用合成样本测试</strong>：测试正常、缺材料、格式错误和权限不足等情况。</li></ol><h2 id="合成示例" tabindex="-1">合成示例 <a class="header-anchor" href="#合成示例" aria-label="Permalink to &quot;合成示例&quot;">​</a></h2><p>将“把一份文字说明转换为五页内部汇报大纲”做成 Skill。Skill 规定输入文件、页面结构、数字核对和输出清单，但不内置任何真实公司模板或材料。</p><h3 id="skill-设计模板" tabindex="-1">Skill 设计模板 <a class="header-anchor" href="#skill-设计模板" aria-label="Permalink to &quot;Skill 设计模板&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Skill 名称：{名称}</span></span>
<span class="line"><span>解决的问题：{一个明确问题}</span></span>
<span class="line"><span>适用场景：{什么时候使用}</span></span>
<span class="line"><span>禁止场景：{什么时候不能使用}</span></span>
<span class="line"><span>必要输入：{文件、字段、授权}</span></span>
<span class="line"><span>执行步骤：{按顺序列出}</span></span>
<span class="line"><span>人工确认点：{暂停并等待确认的位置}</span></span>
<span class="line"><span>输出物：{文件和记录}</span></span>
<span class="line"><span>验收标准：{可检查条件}</span></span>
<span class="line"><span>失败处理：{停止、重试、回退}</span></span>
<span class="line"><span>配套资源：{模板、术语表、样例、检查表}</span></span>
<span class="line"><span>维护信息：{版本、日期、责任人}</span></span></code></pre></div><h2 id="人工确认点" tabindex="-1">人工确认点 <a class="header-anchor" href="#人工确认点" aria-label="Permalink to &quot;人工确认点&quot;">​</a></h2><ul><li>方法是否经过真实任务验证，而非只在纸面上成立。</li><li>配套模板和资料是否允许进入 Skill。</li><li>触发范围是否太宽，是否可能误用。</li><li>高风险动作是否都有明确暂停点。</li></ul><h2 id="输出物与验收标准" tabindex="-1">输出物与验收标准 <a class="header-anchor" href="#输出物与验收标准" aria-label="Permalink to &quot;输出物与验收标准&quot;">​</a></h2><ul><li>Skill 说明可以由新手独立理解。</li><li>输入缺失时会停止并列出缺口。</li><li>输出结构稳定，关键步骤有日志。</li><li>合成测试覆盖成功、失败和回退路径。</li></ul><h2 id="常见弯路与安全边界" tabindex="-1">常见弯路与安全边界 <a class="header-anchor" href="#常见弯路与安全边界" aria-label="Permalink to &quot;常见弯路与安全边界&quot;">​</a></h2><ul><li>把整本制度塞入 Skill，会难以维护。Skill 只保留流程，资料按需引用。</li><li>只写成功路径，遇到异常就会乱试。必须定义停止和回退。</li><li>一次任务就急着固化，容易把偶然做法当标准。先复现再沉淀。</li><li>Skill 不替代正式制度、权限和专业审核；可复用资产包括说明模板、测试样本和版本记录。</li></ul>`,20)])])}const u=a(e,[["render",t]]);export{k as __pageData,u as default};
